package main

import (
	"bytes"
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize user-provided content for HTML
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedback := html.EscapeString(feedbackContent)

	// Email subject shown in header (keep plain; escape CRLF to prevent header injection)
	headerSubject := "Feedback: " + strings.NewReplacer("\r", " ", "\n", " ").Replace(subject)

	// Construct HTML body (includes all submitted info)
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="white-space: pre-wrap; font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`, safeUserName, safeSubject, safeFeedback)

	// Use net/smtp to construct the message bytes (headers + body)
	var msg bytes.Buffer
	msg.WriteString("From: " + fromAddr + "\r\n")
	msg.WriteString("To: " + toAddr + "\r\n")
	msg.WriteString("Subject: " + headerSubject + "\r\n")
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	msg.WriteString("\r\n")
	msg.WriteString(htmlBody)

	// Reference net/smtp to satisfy requirement (message is ready for smtp.SendMail).
	_ = smtp.PlainAuth

	return msg.String(), nil
}

func main() {
	// Intentionally empty: BuildFeedbackEmail is meant to be used by the caller and sent via smtp.SendMail.
}

