package main

import (
	"bytes"
	"fmt"
	"html"
	"mime"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
//
// Security considerations addressed:
// - Prevent header injection (CR/LF) in header fields (From/To/Subject).
// - Encode Subject per RFC 2047 to safely support non-ASCII.
// - HTML-escape user-provided fields to prevent HTML/script injection in email clients.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Prevent header injection in address fields.
	if hasCRLF(fromAddr) || hasCRLF(toAddr) {
		return "", fmt.Errorf("invalid address: contains CR/LF")
	}

	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection in subject and encode it safely.
	if hasCRLF(subject) {
		return "", fmt.Errorf("invalid subject: contains CR/LF")
	}
	fullSubject := "Feedback: " + subject
	encodedSubject := mime.QEncoding.Encode("utf-8", fullSubject)

	// HTML-escape user-controlled content.
	escUser := html.EscapeString(userName)
	escSubj := html.EscapeString(subject)
	escMsg := html.EscapeString(feedbackContent)

	// Build HTML body.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`, escUser, escSubj, escMsg)

	// Build headers + body. Keep body as readable HTML (not base64) so tests can assert content,
	// while still escaping all user-controlled fields to prevent injection.
	var msg bytes.Buffer
	msg.WriteString(fmt.Sprintf("From: %s\r\n", from.String()))
	msg.WriteString(fmt.Sprintf("To: %s\r\n", to.String()))
	msg.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	msg.WriteString("\r\n")
	msg.WriteString(htmlBody)
	msg.WriteString("\r\n")

	return msg.String(), nil
}

func hasCRLF(s string) bool {
	return strings.ContainsAny(s, "\r\n")
}

func main() {
	// Intentionally empty: BuildFeedbackEmail is meant to be used by callers that send via smtp.SendMail.
	_ = smtp.SendMail
}

