// encodeRFC2047 encodes a string as RFC 2047 "encoded-word" using UTF-8 and base64.
func encodeRFC2047(s string) string {
	// If ASCII only, return as-is.
	allASCII := true
	for _, r := range s {
		if r > 127 {
			allASCII = false
			break
		}
	}
	if allASCII {
		return s
	}
	b := base64.StdEncoding.EncodeToString([]byte(s))
	return "=?UTF-8?B?" + b + "?="
}

