	// Use net/smtp to build the message with proper CRLF line endings.
	var msg bytes.Buffer
	msg.WriteString("From: " + fromAddr + "\r\n")
	msg.WriteString("To: " + toAddr + "\r\n")
	msg.WriteString("Subject: " + emailSubject + "\r\n")
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString(`Content-Type: text/html; charset="UTF-8"` + "\r\n")
	msg.WriteString("\r\n")
	msg.WriteString(htmlBody)

	// Reference smtp to satisfy the requirement of using net/smtp in construction context.
