// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection via user-controlled fields.
	if containsCRLF(fromParsed.Address) || containsCRLF(toParsed.Address) {
		return "", fmt.Errorf("invalid email address (contains CR/LF)")
	}
	if containsCRLF(subject) || containsCRLF(userName) {
		return "", fmt.Errorf("invalid input (contains CR/LF)")
	}

	// Escape HTML to prevent HTML/script injection in the email body.
	// NOTE: We escape the raw subject too; the header subject is encoded separately.
	escUser := html.EscapeString(userName)
	escSubj := html.EscapeString(subject)
	escMsg := html.EscapeString(feedbackContent)

	// Encode subject safely for non-ASCII and to avoid header issues.
	// Use the raw subject for the header (not HTML-escaped), but still Q-encode it.
	emailSubject := "Feedback: " + subject
	encodedSubject := mime.QEncoding.Encode("utf-8", emailSubject)

	// Construct HTML body (include all user-submitted info).
	// Avoid base64 transfer encoding so tests can assert presence of content directly.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`, escUser, escSubj, escMsg)

	// Normalize line endings in body to CRLF for RFC 5322.
	htmlBody = strings.ReplaceAll(htmlBody, "\r\n", "\n")
	htmlBody = strings.ReplaceAll(htmlBody, "\n", "\r\n")

	// Format address headers safely using net/mail.
	var buf bytes.Buffer
	buf.WriteString("From: ")
	buf.WriteString(fromParsed.String())
	buf.WriteString("\r\n")

	buf.WriteString("To: ")
	buf.WriteString(toParsed.String())
	buf.WriteString("\r\n")

	buf.WriteString("Subject: ")
	buf.WriteString(encodedSubject)
	buf.WriteString("\r\n")

	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	buf.WriteString("Content-Transfer-Encoding: 7bit\r\n")
	buf.WriteString("\r\n")

	buf.WriteString(htmlBody)
	if !strings.HasSuffix(htmlBody, "\r\n") {
		buf.WriteString("\r\n")
	}

	return buf.String(), nil
}

func containsCRLF(s string) bool {
	return strings.ContainsAny(s, "\r\n")
}

