package main

import (
	"bytes"
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// encodeHeaderRFC2047 encodes a header value per RFC 2047 when it contains
// non-ASCII characters. It also rejects CR/LF to prevent header injection.
func encodeHeaderRFC2047(s string) (string, error) {
	if strings.ContainsAny(s, "\r\n") {
		return "", fmt.Errorf("header value contains invalid newline")
	}
	return mail.Header{"X": []string{s}}.Get("X"), nil
}

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	fromAddr = strings.TrimSpace(fromAddr)
	toAddr = strings.TrimSpace(toAddr)
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize user-provided fields for HTML
	safeUser := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// Construct subject line
	emailSubject := fmt.Sprintf("User Feedback: %s", subject)
	encodedSubject, err := encodeHeaderRFC2047(emailSubject)
	if err != nil {
		return "", err
	}

	// Build the message headers and body
	var msg bytes.Buffer
	msg.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msg.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msg.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	msg.WriteString("Content-Transfer-Encoding: 7bit\r\n")
	msg.WriteString("\r\n")

	// HTML body (includes all submitted info)
	msg.WriteString(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body style="font-family: Arial, sans-serif;">
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> ` + safeUser + `</p>
  <p><strong>Subject:</strong> ` + safeSubject + `</p>
  <div><strong>Message:</strong><br>
    <pre style="white-space: pre-wrap; font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">` + safeContent + `</pre>
  </div>
</body>
</html>`)

	return msg.String(), nil
}

func main() {
	// Intentionally empty. BuildFeedbackEmail is meant to be called by application code.
}

