package main

import (
	"bytes"
	"encoding/base64"
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
	"unicode/utf8"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection via CRLF in any header-derived input.
	// (mail.ParseAddress already rejects many invalid forms, but be explicit.)
	for _, v := range []struct {
		name string
		val  string
	}{
		{"fromAddr", fromAddr},
		{"toAddr", toAddr},
		{"subject", subject},
		{"userName", userName},
	} {
		if strings.ContainsAny(v.val, "\r\n") {
			return "", fmt.Errorf("invalid %s: must not contain CR/LF", v.name)
		}
	}

	// Encode subject safely for non-ASCII and to avoid header issues.
	emailSubject := encodeRFC2047("Feedback: " + subject)

	// HTML-escape user-provided content to prevent HTML/script injection in the email body.
	escUser := html.EscapeString(userName)
	escSubj := html.EscapeString(subject)
	escMsg := html.EscapeString(feedbackContent)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`, escUser, escSubj, escMsg)

	// Build message using net/smtp helpers for proper formatting.
	var msg bytes.Buffer
	msg.WriteString("From: " + from.String() + "\r\n")
	msg.WriteString("To: " + to.String() + "\r\n")
	msg.WriteString("Subject: " + emailSubject + "\r\n")
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString(`Content-Type: text/html; charset="UTF-8"` + "\r\n")
	msg.WriteString("\r\n")
	msg.WriteString(htmlBody)

	return msg.String(), nil
}

// encodeRFC2047 encodes a string for safe use in mail headers (e.g., Subject).
// Uses base64 UTF-8 encoding when non-ASCII is present.
func encodeRFC2047(s string) string {
	// If it's valid ASCII, return as-is.
	for i := 0; i < len(s); i++ {
		if s[i] >= 0x80 {
			// Non-ASCII: encode as RFC 2047 "encoded-word"
			b := base64.StdEncoding.EncodeToString([]byte(s))
			return "=?UTF-8?B?" + b + "?="
		}
	}
	// Also ensure it's valid UTF-8; if not, replace invalid sequences.
	if !utf8.ValidString(s) {
		s = strings.ToValidUTF8(s, "\uFFFD")
	}
	return s
}

func main() {
	// Intentionally empty. This file provides BuildFeedbackEmail for use with smtp.SendMail.
	_ = smtp.SendMail
}

