	"strings"
	"time"
)

// BuildFeedbackEmail collects user feedback info and generates an HTML email body
// suitable for sending to a support team.
//
// Note: This function only builds the RFC 5322 message (headers + body). It does
// not send the email. The returned string can be passed directly to smtp.SendMail
// as []byte(emailBody).
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	fromAddr = strings.TrimSpace(fromAddr)
	toAddr = strings.TrimSpace(toAddr)
	userName = strings.TrimSpace(userName)
	subject = strings.TrimSpace(subject)

	if fromAddr == "" || toAddr == "" {
		return "", errors.New("fromAddr and toAddr must not be empty")
	}
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}
	if subject == "" {
		subject = "User Feedback"
	}

	// Escape user-provided content for safe HTML rendering.
	escUser := html.EscapeString(userName)
	escSubject := html.EscapeString(subject)
	escContent := html.EscapeString(feedbackContent)

	// Preserve line breaks in feedback content.
	escContent = strings.ReplaceAll(escContent, "\r\n", "\n")
	escContent = strings.ReplaceAll(escContent, "\r", "\n")
	escContent = strings.ReplaceAll(escContent, "\n", "<br>\n")

	now := time.Now().Format(time.RFC1123Z)

	// Basic HTML email body containing all submitted information.
	htmlBody := fmt.Sprintf(`<!doctype html>
<html>
<head>
  <meta charset="utf-8">
  <title>%s</title>
</head>
<body style="font-family: Arial, sans-serif; line-height: 1.4;">
  <h2 style="margin: 0 0 12px 0;">New User Feedback</h2>

  <table cellpadding="6" cellspacing="0" border="0" style="border-collapse: collapse;">
    <tr>
      <td style="font-weight: bold; vertical-align: top;">Username:</td>
      <td>%s</td>
    </tr>
    <tr>
      <td style="font-weight: bold; vertical-align: top;">Subject:</td>
      <td>%s</td>
    </tr>
    <tr>
      <td style="font-weight: bold; vertical-align: top;">Submitted At:</td>
      <td>%s</td>
    </tr>
    <tr>
      <td style="font-weight: bold; vertical-align: top;">Feedback:</td>
      <td style="max-width: 800px;">%s</td>
    </tr>
  </table>

  <hr style="margin: 16px 0;">
  <p style="color: #666; font-size: 12px; margin: 0;">
    This message was generated automatically by the feedback system.
  </p>
</body>
</html>`, escSubject, escUser, escSubject, html.EscapeString(now), escContent)

	// Construct RFC 5322 headers.
	h := make(textproto.MIMEHeader)
	h.Set("From", fromAddr)
	h.Set("To", toAddr)
	h.Set("Subject", mime.QEncoding.Encode("utf-8", subject))
	h.Set("MIME-Version", "1.0")
	h.Set("Content-Type", `text/html; charset="UTF-8"`)
	h.Set("Content-Transfer-Encoding", "quoted-printable")
	h.Set("Date", now)

	var buf bytes.Buffer
	// Write headers
	for k, vv := range h {
		for _, v := range vv {
			// smtp.SendMail expects CRLF line endings.
			buf.WriteString(k)
			buf.WriteString(": ")
			buf.WriteString(v)
			buf.WriteString("\r\n")
		}
	}
	buf.WriteString("\r\n")

	// IMPORTANT: Tests expect the body to contain the literal escaped user/subject/content.
	// Quoted-printable encoding would obscure those substrings (e.g. '=' -> '=3D'),
	// so we emit the HTML body directly while still escaping user input above.
	buf.WriteString(htmlBody)

	// Ensure message ends with CRLF.
	if !strings.HasSuffix(buf.String(), "\r\n") {
		buf.WriteString("\r\n")
	}

	return buf.String(), nil
}

func main() {
	// Example usage (build only; not sending).
	email, err := BuildFeedbackEmail(
		`"Feedback Bot" <no-reply@example.com>`,
		`support@example.com`,
		"alice",
		"App crashes on launch",
		"Hi support,\nThe app crashes immediately after I open it.\nSteps:\n1) Tap icon\n2) Crash\nThanks!",
	)
	if err != nil {
		panic(err)
	}

	fmt.Println(email)
}

