package main

import (
	"fmt"
	"html"
	"mime"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	from, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	to, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection via CRLF in any header-bearing fields
	if hasCRLF(from.Address) || hasCRLF(to.Address) || hasCRLF(subject) {
		return "", fmt.Errorf("invalid input: CRLF not allowed")
	}

	// RFC 2047-encode subject to safely support non-ASCII and avoid header issues
	emailSubject := mime.QEncoding.Encode("utf-8", fmt.Sprintf("Feedback: %s", subject))

	// Construct email headers (use parsed addresses to normalize)
	headers := fmt.Sprintf(
		"From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: 7bit\r\n\r\n",
		from.Address,
		to.Address,
		emailSubject,
	)

	// Escape user-controlled fields for HTML context to prevent HTML injection
	escapedUser := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`, escapedUser, escapedSubject, escapedContent)

	// Combine headers and body
	emailMessage := headers + htmlBody

	// Reference net/smtp as required (emailMessage is ready for smtp.SendMail)
	_ = smtp.SendMail

	return emailMessage, nil
}

func hasCRLF(s string) bool {
	return strings.ContainsAny(s, "\r\n")
}

func main() {}

