	"time"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	fromAddr = strings.TrimSpace(fromAddr)
	toAddr = strings.TrimSpace(toAddr)
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection via CR/LF in any header values we control.
	if hasCRLF(fromParsed.Address) || hasCRLF(toParsed.Address) || hasCRLF(subject) {
		return "", fmt.Errorf("invalid input: contains CR/LF")
	}

	// RFC 2047 encode subject to safely support non-ASCII and avoid header issues.
	emailSubject := mime.QEncoding.Encode("utf-8", "Feedback: "+subject)

	// Escape user-provided content for HTML context to prevent HTML injection.
	safeUser := html.EscapeString(userName)
	safeSubj := html.EscapeString(subject)
	safeMsg := html.EscapeString(feedbackContent)

	// Build HTML body (keep escaped user fields as plain text in HTML).
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`, safeUser, safeSubj, safeMsg)

	// Construct the email content.
	var buf bytes.Buffer
	writeHeader(&buf, "From", fromParsed.Address)
	writeHeader(&buf, "To", toParsed.Address)
	writeHeader(&buf, "Subject", emailSubject)
	writeHeader(&buf, "Date", time.Now().Format(time.RFC1123Z))
	writeHeader(&buf, "MIME-Version", "1.0")
	writeHeader(&buf, "Content-Type", `text/html; charset="UTF-8"`)
	// Keep body readable for tests and consumers; do not quoted-printable encode.
	buf.WriteString("\r\n")

	// Normalize line endings in body to CRLF for RFC 5322 compliance.
	buf.WriteString(normalizeCRLF(htmlBody))

	return buf.String(), nil
}

func hasCRLF(s string) bool {
	return strings.ContainsAny(s, "\r\n")
}

func writeHeader(buf *bytes.Buffer, key, value string) {
	key = strings.TrimSpace(key)
	value = strings.TrimSpace(value)
	if hasCRLF(key) || hasCRLF(value) {
		return
	}
	buf.WriteString(key)
	buf.WriteString(": ")
	buf.WriteString(value)
	buf.WriteString("\r\n")
}

func normalizeCRLF(s string) string {
	s = strings.ReplaceAll(s, "\r\n", "\n")
	s = strings.ReplaceAll(s, "\r", "\n")
	return strings.ReplaceAll(s, "\n", "\r\n")
}

func main() {
	// Intentionally empty. BuildFeedbackEmail is meant to be called by application code.
	_ = smtp.SendMail
}

