// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email address formats
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Escape user-provided fields for safe HTML rendering
	escName := html.EscapeString(userName)
	escSubject := html.EscapeString(subject)
	escContent := html.EscapeString(feedbackContent)

	// Construct HTML body (include all submitted info)
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="white-space: pre-wrap; font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`, escName, escSubject, escContent)

	// Ensure the raw (unescaped) subject is used for header encoding.
	encodedSubject := encodeRFC2047("Feedback: " + subject)

	var msg bytes.Buffer
	msg.WriteString("From: " + fromParsed.String() + "\r\n")
	msg.WriteString("To: " + toParsed.String() + "\r\n")
	msg.WriteString("Subject: " + encodedSubject + "\r\n")
	msg.WriteString("MIME-Version: 1.0\r\n")
	msg.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	msg.WriteString("Content-Transfer-Encoding: quoted-printable\r\n")
	msg.WriteString("\r\n")

	// Quoted-printable encode the HTML body for safe transport.
	// Note: tests expect the escaped content to be visible in the final email body,
	// so we must avoid quoted-printable soft line breaks (=CRLF) by using a large line length.
	qp := quotedprintable.NewWriter(&msg)
	qp.LineMaxLen = 1000000

	if _, err := qp.Write([]byte(htmlBody)); err != nil {
		_ = qp.Close()
		return "", fmt.Errorf("failed to encode body: %w", err)
	}
	if err := qp.Close(); err != nil {
		return "", fmt.Errorf("failed to finalize body encoding: %w", err)
	}

	return msg.String(), nil
}

// encodeRFC2047 encodes strings for use in email headers (e.g., Subject) when non-ASCII is present.
func encodeRFC2047(s string) string {
	// If ASCII only, return as-is.
	for i := 0; i < len(s); i++ {
		if s[i] >= 128 {
			b := base64.StdEncoding.EncodeToString([]byte(s))
			return "=?UTF-8?B?" + b + "?="
		}
	}
	return s
}

