	h.Set("From", fromAddr)
	h.Set("To", toAddr)
	h.Set("Subject", fmt.Sprintf("Feedback: %s", subject))
	h.Set("MIME-Version", "1.0")
	h.Set("Content-Type", `text/html; charset="UTF-8"`)

	var buf bytes.Buffer
