			buf.WriteString(k)
			buf.WriteString(": ")
			buf.WriteString(v)
			buf.WriteString("\r\n")
		}
	}
	buf.WriteString("\r\n")
	buf.WriteString(htmlBody)

	// smtp.SendMail expects CRLF line endings; ensure body uses CRLF.
	msg := strings.ReplaceAll(buf.String(), "\n", "\r\n")
	// Avoid doubling CR in already-correct CRLF sequences
