package main

import (
	"bytes"
	"fmt"
	"html"
	"mime"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	fromParsed, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	toParsed, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent header injection via CRLF in user-controlled fields.
	// (fromAddr/toAddr are already parsed, but we still guard against raw CRLF.)
	if containsCRLF(fromAddr) || containsCRLF(toAddr) || containsCRLF(subject) || containsCRLF(userName) {
		return "", fmt.Errorf("invalid input: contains CR/LF")
	}

	// Encode subject safely for non-ASCII and to avoid header issues.
	emailSubject := "Feedback: " + subject
	encodedSubject := mimeEncodeHeader(emailSubject)

	// Escape user-controlled content for HTML context to prevent HTML/script injection.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeFeedback := html.EscapeString(feedbackContent)

	// Build HTML body (escaped content is safe to embed).
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; white-space: pre-wrap;">%s</pre>
  </div>
</body>
</html>`, safeUserName, safeSubject, safeFeedback)

	// Construct RFC 5322 message.
	var buf bytes.Buffer
	buf.WriteString("From: " + fromParsed.String() + "\r\n")
	buf.WriteString("To: " + toParsed.String() + "\r\n")
	buf.WriteString("Subject: " + encodedSubject + "\r\n")
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString(`Content-Type: text/html; charset="UTF-8"` + "\r\n")
	buf.WriteString("Content-Transfer-Encoding: 8bit\r\n")
	buf.WriteString("\r\n")
	buf.WriteString(htmlBody)

	return buf.String(), nil
}

func containsCRLF(s string) bool {
	return strings.ContainsAny(s, "\r\n")
}

// mimeEncodeHeader encodes a header value using RFC 2047 Q-encoding when needed.
func mimeEncodeHeader(v string) string {
	// Use mime.WordEncoder for RFC 2047 encoding.
	// It returns an encoded-word representation; safe for non-ASCII.
	return mime.QEncoding.Encode("utf-8", v)
}

func main() {}

