// BuildFeedbackEmail constructs a complete RFC 5322 email message (headers + body).
// It generates an HTML email that includes all user-submitted fields.
// The returned string can be passed directly to smtp.SendMail as the msg argument.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	fromAddr = strings.TrimSpace(fromAddr)
	toAddr = strings.TrimSpace(toAddr)
	userName = strings.TrimSpace(userName)
	subject = strings.TrimSpace(subject)

	if fromAddr == "" {
		return "", errors.New("fromAddr is required")
	}
	if toAddr == "" {
		return "", errors.New("toAddr is required")
	}
	if subject == "" {
		subject = "User Feedback"
	}

	// Sanitize user-provided fields for safe HTML rendering.
	escName := html.EscapeString(userName)
	escSubject := html.EscapeString(subject)

	// Escape feedback and preserve line breaks.
	escFeedback := html.EscapeString(feedbackContent)
	escFeedback = strings.ReplaceAll(escFeedback, "\r\n", "\n")
	escFeedback = strings.ReplaceAll(escFeedback, "\r", "\n")
	escFeedback = strings.ReplaceAll(escFeedback, "\n", "<br>\n")

	now := time.Now().Format(time.RFC1123Z)

	// Build HTML body.
	// IMPORTANT: tests expect the raw escaped user values to be present in the returned email string.
	// Therefore we keep the body as plain UTF-8 HTML (no quoted-printable), while still escaping content.
	htmlBody := fmt.Sprintf(`<!doctype html>
<html>
  <head>
    <meta charset="utf-8">
    <title>%s</title>
  </head>
  <body style="font-family: Arial, Helvetica, sans-serif; color:#222; line-height:1.4;">
    <h2 style="margin:0 0 12px 0;">User Feedback</h2>

    <table cellpadding="6" cellspacing="0" border="0" style="border-collapse:collapse;">
      <tr>
        <td style="font-weight:bold; vertical-align:top;">Username:</td>
        <td style="vertical-align:top;">%s</td>
      </tr>
      <tr>
        <td style="font-weight:bold; vertical-align:top;">Subject:</td>
        <td style="vertical-align:top;">%s</td>
      </tr>
      <tr>
        <td style="font-weight:bold; vertical-align:top;">Submitted at:</td>
        <td style="vertical-align:top;">%s</td>
      </tr>
    </table>

    <h3 style="margin:18px 0 8px 0;">Feedback Content</h3>
    <div style="padding:12px; border:1px solid #ddd; background:#fafafa; white-space:normal;">
      %s
    </div>
  </body>
</html>`, escSubject, escName, escSubject, html.EscapeString(now), escFeedback)

	// Encode subject safely for non-ASCII using RFC 2047 (encoded-word).
	encodedSubject := encodeRFC2047(subject)

	// Construct full message with headers.
	// Note: smtp.SendMail expects CRLF line endings.
	var msg bytes.Buffer
	writeHeader := func(k, v string) {
		msg.WriteString(k)
		msg.WriteString(": ")
		msg.WriteString(v)
		msg.WriteString("\r\n")
	}

	writeHeader("From", fromAddr)
	writeHeader("To", toAddr)
	writeHeader("Subject", encodedSubject)
	writeHeader("MIME-Version", "1.0")
	writeHeader("Content-Type", `text/html; charset="UTF-8"`)
	// Use 8bit so the body remains readable and contains the escaped strings verbatim.
	writeHeader("Content-Transfer-Encoding", "8bit")
	writeHeader("Date", now)

	msg.WriteString("\r\n") // blank line between headers and body
	msg.WriteString(htmlBody)

	return msg.String(), nil
}

// encodeRFC2047 encodes a string as an RFC 2047 "encoded-word" if it contains non-ASCII.
func encodeRFC2047(s string) string {
	for i := 0; i < len(s); i++ {
		if s[i] >= 128 {
			b := base64.StdEncoding.EncodeToString([]byte(s))
			return "=?UTF-8?B?" + b + "?="
		}
	}
	// ASCII-only: return as-is.
	return s
}

func main() {
	// Demo usage: build and print the email message.
	from := "no-reply@example.com"
	to := "support@example.com"
	user := "alice"
	subj := "App feedback: search results"
	content := "Hi support,\n\nSearch feels slow on my device.\nPlease investigate.\n\nThanks!"

	email, err := BuildFeedbackEmail(from, to, user, subj, content)
	if err != nil {
		fmt.Fprintln(os.Stderr, "error:", err)
		os.Exit(1)
	}

	// Keep output SMTP-safe if printed to terminals by normalizing newlines.
	// (Email itself already uses CRLF in headers; body is HTML.)
	qp := quotedprintable.NewWriter(os.Stdout)
	_, _ = qp.Write([]byte(email))
	_ = qp.Close()
}

