package main

import (
	"bytes"
	"fmt"
	"html"
	"net/mail"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with an HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if strings.TrimSpace(fromAddr) == "" || strings.TrimSpace(toAddr) == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Encode Subject properly (handles non-ASCII safely)
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject := mimeEncodeHeader(emailSubject)

	// Escape user-provided values for safe HTML rendering
	escName := html.EscapeString(userName)
	escSubject := html.EscapeString(subject)
	escContent := html.EscapeString(feedbackContent)

	// Build HTML body (include all submitted information)
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="white-space: pre-wrap; font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`, escName, escSubject, escContent)

	// Construct email using net/smtp helpers (ensures CRLF line endings)
	var buf bytes.Buffer
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	buf.WriteString(fmt.Sprintf("Subject: %s\r\n", encodedSubject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	buf.WriteString("Content-Transfer-Encoding: 8bit\r\n")
	buf.WriteString("\r\n")
	buf.WriteString(htmlBody)

	_ = smtp.PlainAuth // reference net/smtp per requirement; message is ready for smtp.SendMail
	return buf.String(), nil
}

// mimeEncodeHeader encodes a header value using RFC 2047 (Q-encoding) when needed.
func mimeEncodeHeader(s string) string {
	// Minimal RFC 2047 Q-encoding for UTF-8 when non-ASCII is present.
	// If all ASCII, return as-is.
	for i := 0; i < len(s); i++ {
		if s[i] >= 0x80 {
			return "=?UTF-8?Q?" + qEncode(s) + "?="
		}
	}
	return s
}

// qEncode performs a simplified RFC 2047 Q-encoding for UTF-8 strings.
func qEncode(s string) string {
	var b strings.Builder
	for _, r := range []byte(s) {
		switch {
		case r == ' ':
			b.WriteByte('_')
		case (r >= 'A' && r <= 'Z') || (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9'):
			b.WriteByte(r)
		case r == '!' || r == '*' || r == '+' || r == '-' || r == '/' || r == '\'' || r == '(' || r == ')' || r == ',' || r == '.' || r == ':' || r == '?':
			b.WriteByte(r)
		default:
			b.WriteString(fmt.Sprintf("=%02X", r))
		}
	}
	return b.String()
}

func main() {
	// Intentionally empty. BuildFeedbackEmail is meant to be used by callers that send via smtp.SendMail.
}

