<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; white-space: pre-wrap; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`, safeUser, safeSubject, safeFeedback)

	// Encode subject safely for non-ASCII and to avoid header issues
	// NOTE: must use the original subject text (not HTML-escaped) for header encoding.
	encodedSubject := encodeRFC2047("Feedback: " + subject)

	// Construct headers using textproto to ensure proper canonical formatting
	h := make(textproto.MIMEHeader)
	h.Set("From", from.String())
	h.Set("To", to.String())
	h.Set("Subject", encodedSubject)
	h.Set("MIME-Version", "1.0")
	h.Set("Content-Type", `text/html; charset="UTF-8"`)
	h.Set("Content-Transfer-Encoding", "quoted-printable")

	var buf bytes.Buffer
	for k, vv := range h {
		for _, v := range vv {
			// k/v are controlled by us; still ensure no CRLF in values
			if hasCRLF(v) {
