func hasCRLF(s string) bool {
	return strings.ContainsAny(s, "\r\n")
}

// encodeRFC2047 encodes a string per RFC 2047 for safe use in headers.
// Uses base64 for UTF-8 if non-ASCII is present.
func encodeRFC2047(s string) string {
