	emailSubject := fmt.Sprintf("Feedback: %s", strings.TrimSpace(subject))

	// Escape user-controlled content for safe HTML rendering
	escUser := html.EscapeString(userName)
	escSubj := html.EscapeString(subject)
	escMsg := html.EscapeString(feedbackContent)

	// Construct HTML body (include all submitted info)
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
