</html>`, escUser, escSubj, escMsg)

	// Build message using net/smtp helpers for headers
	var buf bytes.Buffer
	buf.WriteString(fmt.Sprintf("From: %s\r\n", fromParsed.String()))
	buf.WriteString(fmt.Sprintf("To: %s\r\n", toParsed.String()))
	buf.WriteString(fmt.Sprintf("Subject: %s\r\n", emailSubject))
	buf.WriteString("MIME-Version: 1.0\r\n")
	buf.WriteString(`Content-Type: text/html; charset="UTF-8"` + "\r\n")
	buf.WriteString("\r\n")
