      <td style="vertical-align: top;">%s</td>
    </tr>
    <tr>
      <td style="font-weight: bold; vertical-align: top;">Subject</td>
      <td style="vertical-align: top;">%s</td>
    </tr>
    <tr>
      <td style="font-weight: bold; vertical-align: top;">Feedback</td>
      <td style="vertical-align: top;">%s</td>
    </tr>
  </table>
  <hr style="margin: 16px 0;">
  <div style="font-size: 12px; color: #555;">
    Generated at %s
  </div>
</body>
</html>`, escSubject, escName, escSubject, escContent, time.Now().Format(time.RFC1123Z))

	// Build RFC 5322 headers.
	h := make(textproto.MIMEHeader)
	h.Set("From", fromAddr)
	h.Set("To", toAddr)
	h.Set("Subject", subject)
	h.Set("MIME-Version", "1.0")
	h.Set("Content-Type", `text/html; charset="UTF-8"`)
